import json
import os
from typing import Any, Dict, Optional

import boto3
from botocore.exceptions import ClientError

sns = boto3.client("sns")

DEFAULT_SUBJECTS = {
    "info": "Information Notification",
    "warning": "Warning Notification",
    "error": "Error Notification",
    "success": "Success Notification",
    "event": "Event Notification",
}


def build_message(notification_type: str, message: Any, event: Dict[str, Any]) -> str:
    if isinstance(message, (dict, list)):
        body = json.dumps(message)
    else:
        body = str(message)

    payload = {
        "notificationType": notification_type,
        "message": body,
        "source": event.get("source", "lambda"),
        "timestamp": event.get("timestamp"),
        "metadata": event.get("metadata", {}),
    }
    return json.dumps(payload)


def resolve_subject(notification_type: str, event: Dict[str, Any]) -> str:
    if event.get("subject"):
        return str(event["subject"])
    return DEFAULT_SUBJECTS.get(notification_type, "SNS Notification")


def publish_to_sns(
    topic_arn: str,
    message: str,
    subject: Optional[str] = None,
    message_attributes: Optional[Dict[str, Dict[str, str]]] = None,
) -> Dict[str, Any]:
    params: Dict[str, Any] = {
        "TopicArn": topic_arn,
        "Message": message,
    }

    if subject:
        params["Subject"] = subject[:100]

    if message_attributes:
        params["MessageAttributes"] = message_attributes

    response = sns.publish(**params)
    return {
        "messageId": response.get("MessageId"),
        "topicArn": topic_arn,
    }


def build_message_attributes(notification_type: str, event: Dict[str, Any]) -> Dict[str, Dict[str, str]]:
    attributes = {
        "notificationType": {
            "DataType": "String",
            "StringValue": notification_type,
        }
    }

    priority = str(event.get("priority", "normal"))
    attributes["priority"] = {
        "DataType": "String",
        "StringValue": priority,
    }

    if "correlationId" in event:
        attributes["correlationId"] = {
            "DataType": "String",
            "StringValue": str(event["correlationId"]),
        }

    return attributes


def parse_event(event: Dict[str, Any]) -> Dict[str, Any]:
    body = event

    if "body" in event:
        raw_body = event["body"]
        if isinstance(raw_body, str):
            body = json.loads(raw_body)
        elif isinstance(raw_body, dict):
            body = raw_body

    return body


def lambda_handler(event, context):
    try:
        payload = parse_event(event)

        topic_arn = payload.get("topicArn") or payload.get("topic_arn") or os.environ.get("DEFAULT_TOPIC_ARN")
        if not topic_arn:
            return {
                "statusCode": 400,
                "body": json.dumps({"error": "Missing topicArn"})
            }

        notification_type = str(payload.get("notificationType", "event")).lower()
        message = payload.get("message")
        if message is None:
            return {
                "statusCode": 400,
                "body": json.dumps({"error": "Missing message"})
            }

        formatted_message = build_message(notification_type, message, payload)
        subject = resolve_subject(notification_type, payload)
        message_attributes = build_message_attributes(notification_type, payload)

        result = publish_to_sns(
            topic_arn=topic_arn,
            message=formatted_message,
            subject=subject,
            message_attributes=message_attributes,
        )

        return {
            "statusCode": 200,
            "body": json.dumps({
                "status": "published",
                "notificationType": notification_type,
                "result": result,
            }),
        }

    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps({
                "error": "SNS publish failed",
                "details": str(e),
            }),
        }
    except Exception as e:
        return {
            "statusCode": 500,
            "body": json.dumps({
                "error": "Unhandled exception",
                "details": str(e),
            }),
        }